import FirebaseFirestore

struct NewsUpdate {
    let title: String
    let content: String
    let date: Date
}

class NewsUpdateService {
    private let firestore: Firestore
    private let demographics: [String: [String]]

    init(firestore: Firestore, demographics: [String: [String]]) {
        self.firestore = firestore
        self.demographics = demographics
    }

    func getNewsUpdates(completion: @escaping ([NewsUpdate]) -> Void) {
        let userID = Auth.auth().currentUser?.uid
        let location = UserLocation.current

        firestore.collection("news_updates").whereField("user_id", isEqualTo: userID).whereField("location", isEqualTo: location).getDocuments { snapshot, error in
            if let error = error {
                completion([NewsUpdate]())
                return
            }

            let newsUpdates = [NewsUpdate]()
            for doc in snapshot!.documents {
                let title = doc["title"].stringValue
                let content = doc["content"].stringValue
                let date = doc["date"].dateValue
                newsUpdates.append(NewsUpdate(title: title, content: content, date: date))
            }

            completion(newsUpdates)
        }
    }

    func getDemographics(completion: @escaping ([String: [String]]) -> Void) {
        let userID = Auth.auth().currentUser?.uid
        firestore.collection("demographics").whereField("user_id", isEqualTo: userID).getDocuments { snapshot, error in
            if let error = error {
